#include <cuda_runtime.h>
#include <iostream>
#include <vector>

#define DATA_SIZE_MB 512
#define THREADS_PER_BLOCK 256
#define TOTAL_THREADS (DATA_SIZE_MB * 1024 * 1024 / sizeof(float))
#define BLOCKS (TOTAL_THREADS + THREADS_PER_BLOCK - 1) / THREADS_PER_BLOCK

__global__ void bandwidth_kernel(float* input, float* output, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) {
        output[idx] = input[idx];
    }
}

int main() {
    const int n = DATA_SIZE_MB * 1024 * 1024 / sizeof(float);

    float *d_input, *d_output;
    cudaMalloc(&d_input, n * sizeof(float));
    cudaMalloc(&d_output, n * sizeof(float));

    // Initialize input data
    cudaMemset(d_input, 1, n * sizeof(float));

    // Warmup - run kernel 3 times
    for(int i = 0; i < 3; i++) {
        bandwidth_kernel<<<BLOCKS, THREADS_PER_BLOCK>>>(d_input, d_output, n);
    }
    cudaDeviceSynchronize();

    // Timing events
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    // Measure multiple iterations
    cudaEventRecord(start);
    for(int i = 0; i < 10; i++) {
        bandwidth_kernel<<<BLOCKS, THREADS_PER_BLOCK>>>(d_input, d_output, n);
    }
    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float elapsed_ms = 0;
    cudaEventElapsedTime(&elapsed_ms, start, stop);
    float elapsed_s = elapsed_ms / 1000.0f;

    size_t bytes_transferred = 2ULL * n * sizeof(float) * 10; // 2 for read+write, 10 iterations
    double bandwidth_gbps = (double)bytes_transferred / (elapsed_s * 1e9);

    printf("%.2f\n", bandwidth_gbps);

    cudaEventDestroy(start);
    cudaEventDestroy(stop);
    cudaFree(d_input);
    cudaFree(d_output);

    return 0;
}

