#include <cuda_runtime.h>
#include <iostream>
#include <vector>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 100
#define SHARED_MEM_SIZE 4096  // 4KB per block
#define THREADS_PER_BLOCK 256
#define NUM_BLOCKS 64

__global__ void shared_memory_bandwidth_kernel(int *dummy_output) {
    __shared__ float smem[SHARED_MEM_SIZE / sizeof(float)];

    int tid = threadIdx.x;
    int bid = blockIdx.x;
    int global_tid = bid * blockDim.x + tid;

    // Initialize shared memory
    for (int i = tid; i < SHARED_MEM_SIZE / sizeof(float); i += blockDim.x) {
        smem[i] = static_cast<float>(global_tid + i);
    }
    __syncthreads();

    clock_t start_cycle = clock64();

    // Perform multiple read/write operations to saturate bandwidth
    for (int iter = 0; iter < MEASURE_ITERATIONS; iter++) {
        // Read from shared memory
        float val = smem[tid];

        // Write back to shared memory
        smem[(tid + 1) % (SHARED_MEM_SIZE / sizeof(float))] = val + 1.0f;

        __syncthreads(); // Synchronize after each iteration to ensure all threads participate

        // Additional accesses to increase utilization
        for (int i = 0; i < 10; i++) {
            int idx = (tid + i) & ((SHARED_MEM_SIZE / sizeof(float)) - 1); // Power of 2 for bank conflict avoidance
            val = smem[idx];
            smem[idx] = val * 2.0f;
        }

        __syncthreads();
    }

    clock_t end_cycle = clock64();

    // Store timing result to prevent optimization
    if (tid == 0) {
        dummy_output[bid] = end_cycle - start_cycle;
    }
}

int main() {
    // Calculate total shared memory used
    size_t total_shared_mem = NUM_BLOCKS * SHARED_MEM_SIZE;
    size_t total_data_accessed = NUM_BLOCKS * THREADS_PER_BLOCK * MEASURE_ITERATIONS * 10 * sizeof(float) * 2; // Read + Write

    // Allocate output buffer for timing results
    int *h_timing_results = new int[NUM_BLOCKS];
    int *d_timing_results;
    cudaMalloc(&d_timing_results, NUM_BLOCKS * sizeof(int));

    // Warmup kernel
    for (int i = 0; i < WARMUP_ITERATIONS; i++) {
        shared_memory_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_timing_results);
    }
    cudaDeviceSynchronize();

    // Measure execution time
    cudaEvent_t start, stop;
    cudaEventCreate(&start);
    cudaEventCreate(&stop);

    cudaEventRecord(start);

    // Actual measurement kernel
    shared_memory_bandwidth_kernel<<<NUM_BLOCKS, THREADS_PER_BLOCK>>>(d_timing_results);

    cudaEventRecord(stop);
    cudaEventSynchronize(stop);

    float elapsed_ms;
    cudaEventElapsedTime(&elapsed_ms, start, stop);

    // Copy timing results back
    cudaMemcpy(h_timing_results, d_timing_results, NUM_BLOCKS * sizeof(int), cudaMemcpyDeviceToHost);

    // Calculate total bytes accessed
    // Each thread does MEASURE_ITERATIONS * 11 accesses (1 initial + 10 in loop) of float values (read + write)
    size_t bytes_per_thread = MEASURE_ITERATIONS * 11 * sizeof(float) * 2; // Read + Write
    size_t total_bytes = NUM_BLOCKS * THREADS_PER_BLOCK * bytes_per_thread;

    float elapsed_seconds = elapsed_ms / 1000.0f;
    double bandwidth_gbps = (double)total_bytes / (elapsed_seconds * 1e9);

    std::cout << bandwidth_gbps << std::endl;

    // Cleanup
    delete[] h_timing_results;
    cudaFree(d_timing_results);
    cudaEventDestroy(start);
    cudaEventDestroy(stop);

    return 0;
}

