#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <algorithm>
#include <vector>
#include <random>

#define WARMUP_ITERATIONS 10
#define MEASURE_ITERATIONS 50
#define CHASE_STEPS 10000
#define DRAM_ARRAY_SIZE_MB 64
#define FLUSH_BUFFER_SIZE_MB 32

__global__ void initializeNodes(int *nodes, int num_nodes) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_nodes) {
        nodes[idx] = (idx + 1) % num_nodes;
    }
}

__global__ void shuffleNodes(int *nodes, int *temp_nodes, int num_nodes, unsigned long long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_nodes) {
        // Simple hash-based pseudo-randomization within a block
        int val = nodes[idx];
        int hash = (val * 2654435761ull) ^ seed;  // Knuth's multiplicative hash
        temp_nodes[idx] = val ^ hash;
    }
}

__global__ void finalizeShuffle(int *nodes, int *indices, int num_nodes) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_nodes) {
        int next_idx = indices[idx];
        nodes[idx] = next_idx;
    }
}

__global__ void flushL2Cache(volatile int *flush_buffer, int size) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int stride = blockDim.x * gridDim.x;

    // Access the entire buffer to flush L2
    for (int i = tid; i < size; i += stride) {
        flush_buffer[i] = flush_buffer[i] + 1;
    }

    // Additional accesses to ensure full flush
    for (int i = tid; i < size / 2; i += stride) {
        flush_buffer[i] = flush_buffer[i] + 1;
    }
}

__global__ void __launch_bounds__(1) 
measureDramLatencyCycles(volatile int *nodes, int start_idx, int num_nodes, unsigned long long *results, int iteration) {
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid != 0) return;  // Only first thread does the measurement

    unsigned long long start_cycle, end_cycle;

    // Warmup
    int current_idx = start_idx;
    for (int i = 0; i < 100; i++) {
        current_idx = nodes[current_idx];
    }

    // Actual measurement
    start_cycle = clock64();
    for (int i = 0; i < CHASE_STEPS; i++) {
        current_idx = nodes[current_idx];
    }
    end_cycle = clock64();

    results[iteration] = (end_cycle - start_cycle) / CHASE_STEPS;
}

__global__ void createRandomPermutation(int *nodes, int num_nodes, unsigned long long seed) {
    // Create a random permutation using a simple PRNG approach
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    int total_threads = blockDim.x * gridDim.x;

    // Each thread processes multiple elements
    for (int i = tid; i < num_nodes; i += total_threads) {
        // Use linear congruential generator to get a pseudo-random index
        unsigned long long val = (seed + i) * 1103515245ULL + 12345ULL;
        val = (val >> 16) % num_nodes;
        nodes[i] = val;
    }
}

__global__ void fixPermutation(int *nodes, int *temp, int num_nodes) {
    // Ensure we have a valid permutation by fixing duplicates
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid < num_nodes) {
        temp[tid] = tid;  // Initialize temp with indices
    }
}

void runBenchmark() {
    const int num_nodes = (DRAM_ARRAY_SIZE_MB * 1024 * 1024) / 128;  // 128 bytes per node
    const int flush_size = (FLUSH_BUFFER_SIZE_MB * 1024 * 1024) / sizeof(int);

    int *h_nodes = new int[num_nodes];
    int *d_nodes, *d_temp, *d_flush_buffer;
    unsigned long long *d_results;

    cudaMalloc(&d_nodes, num_nodes * sizeof(int));
    cudaMalloc(&d_temp, num_nodes * sizeof(int));
    cudaMalloc(&d_flush_buffer, flush_size * sizeof(int));
    cudaMalloc(&d_results, MEASURE_ITERATIONS * sizeof(unsigned long long));

    // Initialize nodes as a simple sequence
    initializeNodes<<<(num_nodes + 255) / 256, 256>>>(d_nodes, num_nodes);
    cudaDeviceSynchronize();

    // Create a random permutation to defeat prefetcher
    createRandomPermutation<<<(num_nodes + 255) / 256, 256>>>(d_nodes, num_nodes, 123456ULL);
    cudaDeviceSynchronize();

    // Fix permutation to ensure it's valid
    fixPermutation<<<(num_nodes + 255) / 256, 256>>>(d_nodes, d_temp, num_nodes);
    cudaDeviceSynchronize();

    // Launch configuration for single-threaded measurement
    dim3 block(1);
    dim3 grid(1);

    std::vector<unsigned long long> latencies;

    for (int iter = 0; iter < MEASURE_ITERATIONS + WARMUP_ITERATIONS; iter++) {
        // Flush L2 cache before each measurement
        flushL2Cache<<<(flush_size + 255) / 256, 256>>>(d_flush_buffer, flush_size);
        cudaDeviceSynchronize();

        if (iter >= WARMUP_ITERATIONS) {
            measureDramLatencyCycles<<<grid, block>>>(d_nodes, 0, num_nodes, d_results, iter - WARMUP_ITERATIONS);
            cudaDeviceSynchronize();

            unsigned long long result;
            cudaMemcpy(&result, d_results, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
            latencies.push_back(result);
        }
    }

    // Calculate median
    std::sort(latencies.begin(), latencies.end());
    unsigned long long median_latency = latencies[latencies.size() / 2];

    printf("%llu\n", median_latency);

    delete[] h_nodes;
    cudaFree(d_nodes);
    cudaFree(d_temp);
    cudaFree(d_flush_buffer);
    cudaFree(d_results);
}

int main() {
    runBenchmark();
    return 0;
}

