#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <algorithm>
#include <vector>
#include <random>

#define WARMUP_ITERATIONS 5
#define MEASURE_ITERATIONS 20
#define CHASE_STEPS 5000
#define NUM_SIZES 15
#define FINE_NUM_SIZES 11

// Array of sizes to test in KB
const int sizes_kb[NUM_SIZES] = {128, 256, 512, 1024, 1536, 2048, 2560, 3072, 3584, 4096, 5120, 6144, 8192, 12288, 16384};

__global__ void initializeArray(int *arr, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) {
        arr[idx] = (idx + 1) % n;
    }
}

__global__ void createRandomPermutation(int *arr, int n, unsigned long long seed) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n) {
        // Simple hash-based randomization
        unsigned long long val = seed ^ idx;
        val = val * 1103515245ULL + 12345ULL;
        val = val ^ (val >> 16);
        val = val * 9223372036854775807ULL; // Large prime
        val = val ^ (val >> 32);
        int random_idx = val % n;

        // Swap elements
        int temp = arr[idx];
        arr[idx] = arr[random_idx];
        arr[random_idx] = temp;
    }
}

__global__ void pointerChase(volatile int *nodes, int start_idx, int n, unsigned long long *result, int iteration) {
    int tid = threadIdx.x + blockIdx.x * blockDim.x;
    if (tid != 0) return; // Only first thread does the chase

    unsigned long long start_cycle, end_cycle;

    // Warmup
    int current = start_idx;
    for (int i = 0; i < 100; i++) {
        current = nodes[current];
    }

    // Measurement
    start_cycle = clock64();
    for (int i = 0; i < CHASE_STEPS; i++) {
        current = nodes[current];
    }
    end_cycle = clock64();

    result[iteration] = (end_cycle - start_cycle) / CHASE_STEPS;
}

double measureLatencyAtSize(int size_kb) {
    int num_ints = (size_kb * 1024) / sizeof(int);

    int *d_arr;
    unsigned long long *d_result;

    cudaMalloc(&d_arr, num_ints * sizeof(int));
    cudaMalloc(&d_result, MEASURE_ITERATIONS * sizeof(unsigned long long));

    // Initialize array as a sequence
    dim3 block(256);
    dim3 grid((num_ints + block.x - 1) / block.x);
    initializeArray<<<grid, block>>>(d_arr, num_ints);
    cudaDeviceSynchronize();

    // Create random permutation to defeat prefetcher
    createRandomPermutation<<<grid, block>>>(d_arr, num_ints, 123456ULL);
    cudaDeviceSynchronize();

    // Measure latency
    std::vector<unsigned long long> latencies;
    for (int iter = 0; iter < MEASURE_ITERATIONS + WARMUP_ITERATIONS; iter++) {
        pointerChase<<<1, 1>>>(d_arr, 0, num_ints, d_result, iter);
        cudaDeviceSynchronize();

        if (iter >= WARMUP_ITERATIONS) {
            unsigned long long latency;
            cudaMemcpy(&latency, d_result + (iter - WARMUP_ITERATIONS), sizeof(unsigned long long), cudaMemcpyDeviceToHost);
            latencies.push_back(latency);
        }
    }

    // Calculate median latency
    std::sort(latencies.begin(), latencies.end());
    double median = latencies[latencies.size() / 2];

    cudaFree(d_arr);
    cudaFree(d_result);

    return median;
}

int main() {
    std::vector<double> latencies;
    std::vector<int> sizes_tested;

    // Coarse sweep
    for (int i = 0; i < NUM_SIZES; i++) {
        double latency = measureLatencyAtSize(sizes_kb[i]);
        latencies.push_back(latency);
        sizes_tested.push_back(sizes_kb[i]);
        printf("Size: %d KB, Latency: %.2f cycles\n", sizes_kb[i], latency);
    }

    // Find the cliff point - where latency increases significantly
    int cliff_idx = 0;
    double max_diff = 0.0;
    for (int i = 1; i < latencies.size(); i++) {
        double diff = latencies[i] - latencies[i-1];
        if (diff > max_diff) {
            max_diff = diff;
            cliff_idx = i;
        }
    }

    // If we found a significant jump, do fine-grained search around it
    int l2_size_kb;
    if (cliff_idx > 0 && max_diff > 0.0) {
        int base_size = sizes_tested[cliff_idx - 1];
        int top_size = sizes_tested[cliff_idx];

        // Perform fine-grained search between these two points
        std::vector<double> fine_latencies;
        std::vector<int> fine_sizes;

        int step_size = (top_size - base_size) / (FINE_NUM_SIZES - 1);
        if (step_size == 0) step_size = 1;

        for (int i = 0; i < FINE_NUM_SIZES; i++) {
            int size = base_size + i * step_size;
            if (size > top_size) size = top_size;

            double latency = measureLatencyAtSize(size);
            fine_latencies.push_back(latency);
            fine_sizes.push_back(size);
            printf("Fine: %d KB, Latency: %.2f cycles\n", size, latency);
        }

        // Find cliff in fine-grained data
        int fine_cliff_idx = 0;
        double fine_max_diff = 0.0;
        for (int i = 1; i < fine_latencies.size(); i++) {
            double diff = fine_latencies[i] - fine_latencies[i-1];
            if (diff > fine_max_diff) {
                fine_max_diff = diff;
                fine_cliff_idx = i;
            }
        }

        if (fine_cliff_idx > 0) {
            l2_size_kb = fine_sizes[fine_cliff_idx - 1];
        } else {
            l2_size_kb = sizes_tested[cliff_idx - 1];
        }
    } else {
        // If no clear cliff found, use the original detection
        if (cliff_idx > 0) {
            l2_size_kb = sizes_tested[cliff_idx - 1];
        } else {
            l2_size_kb = 1024; // Default fallback
        }
    }

    printf("%d\n", l2_size_kb);
    return 0;
}

