#include <cuda_runtime.h>
#include <stdio.h>
#include <algorithm>

#define WARP_SIZE 32
#define NUM_THREADS_PER_BLOCK 256
#define NUM_ACCESSES 100
#define SHARED_MEM_SIZE (NUM_THREADS_PER_BLOCK * sizeof(long long))

__global__ void conflict_free_kernel(volatile long long* smem, long long* result) {
    __shared__ volatile long long sdata[SHARED_MEM_SIZE / sizeof(long long)];

    int tid = threadIdx.x;
    long long start = clock64();

    // Conflict-free access: each thread accesses its own element
    for (int i = 0; i < NUM_ACCESSES; i++) {
        sdata[tid] = tid + i;
    }
    __syncthreads();

    for (int i = 0; i < NUM_ACCESSES; i++) {
        long long val = sdata[tid];
        // Use the value to prevent optimization
        if (val == -1) {  // This condition will never be true
            *result = val;
        }
    }

    long long end = clock64();
    *result = end - start;
}

__global__ void conflict_kernel(volatile long long* smem, long long* result) {
    __shared__ volatile long long sdata[SHARED_MEM_SIZE / sizeof(long long)];

    int tid = threadIdx.x;
    long long start = clock64();

    // Create bank conflicts: all threads in a warp access the same bank
    // Bank index = (address / sizeof(long long)) % 32
    // If we access sdata[tid * 32], all threads access bank 0
    for (int i = 0; i < NUM_ACCESSES; i++) {
        sdata[(tid * 32) % (SHARED_MEM_SIZE / sizeof(long long))] = tid + i;
    }
    __syncthreads();

    for (int i = 0; i < NUM_ACCESSES; i++) {
        long long val = sdata[(tid * 32) % (SHARED_MEM_SIZE / sizeof(long long))];
        // Use the value to prevent optimization
        if (val == -1) {  // This condition will never be true
            *result = val;
        }
    }

    long long end = clock64();
    *result = end - start;
}

int main() {
    const int num_iterations = 10;
    long long conflict_times[num_iterations];
    long long free_times[num_iterations];

    long long *d_result;
    cudaMalloc(&d_result, sizeof(long long));

    // Warm up
    conflict_free_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(nullptr, d_result);
    conflict_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(nullptr, d_result);
    cudaDeviceSynchronize();

    // Measure conflict-free time
    for (int i = 0; i < num_iterations; i++) {
        conflict_free_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(nullptr, d_result);
        cudaDeviceSynchronize();
        cudaMemcpy(&free_times[i], d_result, sizeof(long long), cudaMemcpyDeviceToHost);
    }

    // Measure conflict time
    for (int i = 0; i < num_iterations; i++) {
        conflict_kernel<<<1, NUM_THREADS_PER_BLOCK>>>(nullptr, d_result);
        cudaDeviceSynchronize();
        cudaMemcpy(&conflict_times[i], d_result, sizeof(long long), cudaMemcpyDeviceToHost);
    }

    // Calculate medians
    std::sort(free_times, free_times + num_iterations);
    std::sort(conflict_times, conflict_times + num_iterations);

    long long median_free = free_times[num_iterations / 2];
    long long median_conflict = conflict_times[num_iterations / 2];

    // Calculate penalty per access per thread
    long long total_accesses = WARP_SIZE * NUM_ACCESSES;
    double penalty = static_cast<double>(median_conflict - median_free) / total_accesses;

    printf("%.2f\n", penalty);

    cudaFree(d_result);
    return 0;
}
